    {
      "title": "BIBB/BAuA Employment Survey of the Working Population on Qualification and Working Conditions in Germany 2018",
      "collection_mode": "CATI (Computer Assisted Telephone Interview)",
      "country": ["Germany"],
      "year": 2018,
      "keywords": ["digitalization", "telecommuting", "workaholism", "job performance"],
      "description": "National telephone survey of employed persons in Germany focusing on qualifications and working conditions. Includes modules on digital tools at work, mobile work/home office, work intensity and health, enabling analyses related to telecommuting and aspects of job performance."
    },
    {
      "title": "BIBB/BAuA Employment Survey of the Working Population on Qualification and Working Conditions in Germany 2012",
      "collection_mode": "CATI (Computer Assisted Telephone Interview)",
      "country": ["Germany"],
      "year": 2012,
      "keywords": ["digitalization", "telecommuting", "workaholism", "job performance"],
      "description": "Telephone survey of employed persons in Germany on qualifications and working conditions. Contains indicators on ICT use, flexible working arrangements (including working from home/mobile work), and work strain, supporting research into digitalization and telecommuting."
    },
    {
      "title": "BIBB/BAuA Employment Survey of the Working Population on Qualification and Working Conditions in Germany 2006",
      "collection_mode": "CATI (Computer Assisted Telephone Interview)",
      "country": ["Germany"],
      "year": 2006,
      "keywords": ["digitalization", "telecommuting", "workaholism", "job performance"],
      "description": "CATI survey covering qualifications, working conditions, and aspects of work organization among employees in Germany. Includes variables on ICT at work and flexible work arrangements relevant to telecommuting and related outcomes."
    }
